INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-03181', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關問卷裡問項先後順序的說法，何者正確？①為防回答者沒耐性，最好開始就問有壓迫性的問題', '["為避免回答者不仔細看題目，最好不按邏輯順序交雜詢問不同主題問項", "問卷問項先後順序影響回 答者作答的現象稱順序效果（order effect）", "順序效果對持中立態度者與低教育程度者影響較大  ⑤先 問一般問題再問特殊問題的順序安排稱為漏斗順序（funnel sequence）", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03182', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '請挑出有關郵寄問卷、電話訪談、與面對面訪談的錯誤敘述：', '["以成本高低排序：面對面訪談＞電話訪談＞郵寄問卷", "以速度快慢排序：面對面訪談＞電話訪談＞郵寄問卷", "以回答率高低排序：面對面訪談＞電話訪談＞郵寄問卷", "以社會期望偏誤高低排序：面對面訪談＞電話訪談＞郵寄問卷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03183', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關紥根理論（grounded theory）的敘述，何者正確？①它是一個從上往下的演繹過程  ②主旨在否證研究', '["不斷在資料、理論及彼此之間持續比較", "理論抽樣（theoretical sampling）是 挑取受訪者的關鍵  ⑤理論飽和（theoretical saturated）是它的終點", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03184', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關焦點團體訪談的敘述，何者正確？', '["是對一群人所進行的共同訪談，它的主題一致、所討論內容和個別訪談相同", "參與者是根據所討論主題的關聯程度隨機抽選出來的", "團體動力也有可能形成壓力，讓參與者不敢或不願表示意見", "所蒐集資料的訊息集中、有系統性，比較容易進行分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03185', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為避免社會工作評估過程中，社會工作者的主觀期望有意無意間影響了案主的回答，我們可考慮採用：', '["開放實驗設計", "霍桑實驗設計", "單盲實驗設計", "雙盲實驗設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03186', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '直接使用「臺灣世界價值觀調查」資料庫，研究國人子女教養及婚姻態度等價值變化，在方法上它屬於：', '["問卷調查", "敘事研究", "歷史分析", "次級資料分析"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03187', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '相較其他研究方法，下列有關內容分析的敘述，何者錯誤？', '["費錢、耗時是它的缺點", "不介入、容易更正錯誤是它的優點", "它可以是量化的，也可以是質化的技術", "它可以應用在對社會工作個案紀錄的分析上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03188', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '實驗設計（experimental design）與準實驗設計（quasi-experimental design）二者最主要差異是：', '["控制組人數", "對照組人數", "取樣單位隨機化", "實驗組人數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03189', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何種情形，採用中位數（median）要比使用平均數（mean）適當？', '["平均數值很大時", "需要有高效度時", "平均數與眾數相差太大時", "極端分數對於平均數影響太大時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03190', 'social-worker', 'social-worker-moex-100-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當進行統計顯著性檢定時，發現p＜0.05顯著水準，研究者拒絕虛無假設時，下列敘述何者正確？', '["以這個樣本結果來推論母群體時，只有小於5%的可能性是由抽樣誤差所造成的", "有高於或等於95%的機會，樣本結果純粹的由機會所造成，而它可以充分反映母群體特質", "我們有高於或等於95%的信心，認為虛無假設是正確，而虛無假設是研究者內心所支持的", "當p＜0.05時會出現一顆星星（*），它直接證明了變項和變項之間的確有關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "67ea4588de46", "answer_pdf_sha1": "babc3c5cb0bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
